type testsummaryPaginateArgs struct {
	first, last   *int
	after, before *Cursor
	opts          []TestSummaryPaginateOption
}

func newTestSummaryPaginateArgs(rv map[string]any) *testsummaryPaginateArgs {
	args := &testsummaryPaginateArgs{}
	if rv == nil {
		return args
	}
	if v := rv[firstField]; v != nil {
		args.first = v.(*int)
	}
	if v := rv[lastField]; v != nil {
		args.last = v.(*int)
	}
	if v := rv[afterField]; v != nil {
		args.after = v.(*Cursor)
	}
	if v := rv[beforeField]; v != nil {
		args.before = v.(*Cursor)
	}
	if v, ok := rv[orderByField]; ok {
		switch v := v.(type) {
		case map[string]any:
			var (
				err1, err2 error
				order      = &TestSummaryOrder{Field: &TestSummaryOrderField{}, Direction: entgql.OrderDirectionAsc}
			)
			if d, ok := v[directionField]; ok {
				err1 = order.Direction.UnmarshalGQL(d)
			}
			if f, ok := v[fieldField]; ok {
				err2 = order.Field.UnmarshalGQL(f)
			}
			if err1 == nil && err2 == nil {
				args.opts = append(args.opts, WithTestSummaryOrder(order))
			}
		case *TestSummaryOrder:
			if v != nil {
				args.opts = append(args.opts, WithTestSummaryOrder(v))
			}
		}
	}
	if v, ok := rv[whereField].(*TestSummaryWhereInput); ok {
		args.opts = append(args.opts, WithTestSummaryFilter(v.Filter))
	}
	return args
}

